export const THEME_IDS = ["t3-dark", "t3-light", "t3-midnight"] as const;
export type ThemeId = (typeof THEME_IDS)[number];

export type StoredTheme = ThemeId | "system";

export interface ThemeColorTokens {
  /** Main page background */
  background: string;
  /** Main text color */
  foreground: string;
  /** Accent / highlight color (maps to --primary) */
  accent: string;
  /** Sidebar surface background */
  sidebar: string;
  /** Editor / chat panel background */
  editor: string;
  /** Terminal background */
  terminal: string;
  /** Terminal text / foreground */
  terminalForeground: string;
  /** Status bar background */
  statusBar: string;
  /** Status bar text / foreground */
  statusBarForeground: string;
}

export interface AppTheme {
  readonly id: ThemeId;
  readonly name: string;
  readonly isDark: boolean;
  readonly colors: ThemeColorTokens;
  /**
   * Fully-resolved CSS custom property values to apply to documentElement via
   * style.setProperty(). Must use raw CSS values (hex, oklch, rgba) — no
   * var() references, no Tailwind --alpha() functions.
   */
  readonly cssVars: Record<string, string>;
}

const T3_LIGHT_CSS_VARS: Record<string, string> = {
  "--background": "#ffffff",
  "--foreground": "#262626",
  "--card": "#ffffff",
  "--card-foreground": "#262626",
