import { createContext, useContext, type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

type ThemeContextValue = ReturnType<typeof useTheme>;

const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides the current theme state to the React tree via context.
 * `useTheme()` continues to work anywhere without this provider (module-level
 * singleton), but wrapping with ThemeProvider also exposes `useThemeContext()`
 * as an opt-in context accessor.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const value = useTheme();
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Read the current theme from React context. Must be called inside a
 * ThemeProvider. Prefer `useTheme()` for components that are already
 * directly consuming the hook.
 */
export function useThemeContext(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useThemeContext must be called inside a ThemeProvider");
  return ctx;
}

