import { BUILT_IN_THEMES, THEME_IDS, getBuiltInTheme, type ThemeId } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

const SYSTEM_OPTION = {
  value: "system" as const,
  label: "System",
  description: "Follow your OS light/dark preference.",
};

function ThemeSwatches({ themeId }: { themeId: ThemeId }) {
  const t = getBuiltInTheme(themeId);
  const swatches: Array<{ color: string; label: string }> = [
    { color: t.colors.background, label: "Background" },
    { color: t.colors.sidebar, label: "Sidebar" },
    { color: t.colors.accent, label: "Accent" },
    { color: t.colors.terminal, label: "Terminal" },
    { color: t.colors.statusBar, label: "Status bar" },
  ];

  return (
    <div className="mt-2 flex items-center gap-1.5" aria-hidden="true">
      {swatches.map((swatch) => (
        <span
          key={swatch.label}
          title={swatch.label}
          className="h-4 w-4 shrink-0 rounded-full border border-black/10 dark:border-white/10"
          style={{ background: swatch.color }}
        />
      ))}
    </div>
  );
}

/**
 * Theme selector component for the Settings page Appearance section.
 * Renders 3 built-in theme cards with color swatches plus a System option.
 */
export function ThemeSelector() {
  const { theme, setTheme, appTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme selection">
      {THEME_IDS.map((id) => {
        const builtIn = getBuiltInTheme(id);
        const selected = theme === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full flex-col rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(id)}
          >
            <div className="flex w-full items-center justify-between">
              <span className="text-sm font-medium">{builtIn.name}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </div>
            <ThemeSwatches themeId={id} />
          </button>
        );
      })}

      {/* System option */}
      {(() => {
        const selected = theme === "system";
        return (
          <button
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-start justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme("system")}
          >
            <span className="flex flex-col">
              <span className="text-sm font-medium">{SYSTEM_OPTION.label}</span>
              <span className="text-xs">{SYSTEM_OPTION.description}</span>
            </span>
            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })()}

      <p className="mt-1 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{appTheme.name}</span>
      </p>
    </div>
  );
}

